    }

    return {
      ok: true,
      degraded: false,
      detectedVersion,
      testedVersions,
      unknownVersion
    };
  } catch (error: unknown) {
    return {
      ok: false,
      degraded: true,
      detectedVersion,
      testedVersions,
      unknownVersion,
      error: error instanceof Error ? error.message : String(error)
    };
  }
